// Extract YouTube video ID from URL and pass through record_id
const input = $input.first().json;
const url = input.youtube_url || '';

// Support all YouTube URL formats
const patterns = [
  /[?&]v=([a-zA-Z0-9_-]{11})/,
  /youtu\.be\/([a-zA-Z0-9_-]{11})/,
  /embed\/([a-zA-Z0-9_-]{11})/,
  /shorts\/([a-zA-Z0-9_-]{11})/
];

let video_id = null;
for (const pattern of patterns) {
  const match = url.match(pattern);
  if (match) {
    video_id = match[1];
    break;
  }
}

if (!video_id) {
  throw new Error('Could not extract YouTube video ID from URL: ' + url);
}

return [{
  json: {
    record_id: input.record_id,
    youtube_url: url,
    video_id
  }
}];

// Parse YouTube timedtext JSON3 format and extract plain text
// Preserves record_id and video_id from previous node
const prev = $('Extract Video ID').first().json;
const response = $input.first().json;

let transcript = '';
let has_content = false;

try {
  // Timedtext JSON3 format: { events: [{ segs: [{ utf8: '...' }] }] }
  if (response.events && Array.isArray(response.events) && response.events.length > 0) {
    const parts = [];
    for (const event of response.events) {
      if (event.segs && Array.isArray(event.segs)) {
        for (const seg of event.segs) {
          if (seg.utf8 && seg.utf8.trim()) {
            parts.push(seg.utf8);
          }
        }
      }
    }
    const raw = parts.join('');
    // Clean up whitespace and newlines
    transcript = raw.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
    has_content = transcript.length > 50;
  }
} catch (e) {
  // Parse error — has_content stays false, falls through to fallback
}

return [{
  json: {
    record_id: prev.record_id,
    youtube_url: prev.youtube_url,
    video_id: prev.video_id,
    transcript,
    has_content,
    method: 'timedtext_asr'
  }
}];

// Parse manual captions (same format as ASR, without kind=asr)
const prev = $('Parse Timedtext ASR').first().json;
const response = $input.first().json;

let transcript = '';
let has_content = false;

try {
  if (response.events && Array.isArray(response.events) && response.events.length > 0) {
    const parts = [];
    for (const event of response.events) {
      if (event.segs && Array.isArray(event.segs)) {
        for (const seg of event.segs) {
          if (seg.utf8 && seg.utf8.trim()) {
            parts.push(seg.utf8);
          }
        }
      }
    }
    const raw = parts.join('');
    transcript = raw.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
    has_content = transcript.length > 50;
  }
} catch (e) {
  // Parse error
}

return [{
  json: {
    record_id: prev.record_id,
    youtube_url: prev.youtube_url,
    video_id: prev.video_id,
    transcript,
    has_content,
    method: 'timedtext_manual'
  }
}];

// Extract AssemblyAI job ID from submission response
const prev = $('Parse Timedtext Manual').first().json;
const response = $input.first().json;

if (!response.id) {
  return [{ json: {
    record_id: prev.record_id,
    job_id: null,
    submit_failed: true,
    submit_error: 'AssemblyAI submission failed: ' + (response.error || response.message || JSON.stringify(response))
  }}];
}

return [{ json: {
  record_id: prev.record_id,
  job_id: response.id,
  submit_failed: false,
  submit_error: ''
}}];

// Format AssemblyAI result into standard transcribe_v2 output format
const jobInfo = $('Extract Job ID').first().json;
const pollResponse = $input.first().json;

// Handle submission failure (job_id was null)
if (jobInfo.submit_failed) {
  return [{ json: {
    record_id: jobInfo.record_id,
    transcript: '',
    method: 'none',
    success: false,
    error: jobInfo.submit_error
  }}];
}

// Handle completed transcription
if (pollResponse.status === 'completed') {
  return [{ json: {
    record_id: jobInfo.record_id,
    transcript: pollResponse.text || '',
    method: 'assemblyai',
    success: true,
    error: ''
  }}];
}

// Handle error status
if (pollResponse.status === 'error') {
  return [{ json: {
    record_id: jobInfo.record_id,
    transcript: '',
    method: 'none',
    success: false,
    error: 'AssemblyAI transcription failed: ' + (pollResponse.error || 'unknown error')
  }}];
}

// Not ready after 60s wait (status: queued or processing)
return [{ json: {
  record_id: jobInfo.record_id,
  transcript: '',
  method: 'none',
  success: false,
  error: 'AssemblyAI not ready after 60s. Status: ' + (pollResponse.status || 'unknown') + '. Job ID: ' + jobInfo.job_id + '. Retry or increase wait time.'
}}];
